-- ============================================
-- Legislacao full-site: fabio-mitidieri / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/178969
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = fabio-mitidieri-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 71
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=178969, tipo Deputado(a), ordemAssinatura=1.
-- 29 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'fabio-mitidieri';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'fabio-mitidieri: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao fabio-mitidieri: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2325027', '2313281', '2308548', '2308474', '2301540', '2295349', '2325030', '2283019', '2325929', '2325927', '2325072', '2325028', '2325024', '2313282', '2308551', '2308549', '2308478', '2308476', '2308472', '2308470', '2308467', '2308462', '2302194', '2302191', '2325025', '2308545', '2308473', '2308468', '2301632', '2299012', '2293794', '2287256', '2282688', '2277501', '2234474', '2225794', '2314046', '2308550', '2308477', '2308471', '2308466', '2302193', '2301542', '2295802', '2286305', '2285154', '2279607', '2276636', '2260656', '2229249', '2308469', '2308036', '2302190', '2294204', '2289523', '2286217', '2279488', '2234575', '2226395', '2301631', '2298990', '2282391', '2276708', '2229250', '2225123', '2279604', '2275922', '2242711', '2226648', '2286301', '2325073');
  IF target_present <> 71 THEN
    RAISE EXCEPTION 'Pre-condicao fabio-mitidieri: esperadas 71 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2325027', '2313281', '2308548', '2308474', '2301540', '2295349', '2325030', '2283019', '2325929', '2325927', '2325072', '2325028', '2325024', '2313282', '2308551', '2308549', '2308478', '2308476', '2308472', '2308470', '2308467', '2308462', '2302194', '2302191', '2325025', '2308545', '2308473', '2308468', '2301632', '2299012', '2293794', '2287256', '2282688', '2277501', '2234474', '2225794', '2314046', '2308550', '2308477', '2308471', '2308466', '2302193', '2301542', '2295802', '2286305', '2285154', '2279607', '2276636', '2260656', '2229249', '2308469', '2308036', '2302190', '2294204', '2289523', '2286217', '2279488', '2234575', '2226395', '2301631', '2298990', '2282391', '2276708', '2229250', '2225123', '2279604', '2275922', '2242711', '2226648', '2286301', '2325073')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'fabio-mitidieri-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao fabio-mitidieri: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao fabio-mitidieri: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

